import { useContext, useEffect, useState } from "react"
import AppContext from "../../context"
import { useNavigate, useLocation, useParams } from "react-router-dom"
import { MachineService } from "../../services/machine"
import { MachineEntity } from "../../entities/MachineEntity"
import { AlertEntity } from "../../layouts/Alert/AlertEntity"
import styles from './DashboardLevel3.module.css'
import { formatDate } from "date-fns"
import followingErrorImage from "../../assets/images/error_image.png"
import cardImage from "../../assets/images/machine_image.png"
import { DashboardFollowingLevel3 } from "../../entities/FollowingErrorEntity"
import { DashboardFollErrService } from "../../services/following_error"

interface FilterType {
    start_date: Date
    end_date: Date
}

interface DashboardLevel3FollErrPageProps {
    realtime: boolean
    refresh: number
    filterDate: FilterType
    onFilterDateChange: (newFilter: FilterType) => void
}

const DashboardLevel3FollErrPage: React.FC<DashboardLevel3FollErrPageProps> = ({ realtime, refresh, filterDate, onFilterDateChange }) => {
    // ========================================= GLOBAL CONTEXT =========================================  //
    const context = useContext(AppContext)
    const contextVersion = context.version
    const contextAccessToken = context.contextAccessToken
    const contextShowAlertFunc = context.contextShowAlertFunc
    const contextShowLoadingFunc = context.contextShowLoadingFunc
    const stateShowLoading = context.stateShowLoading
    const navigate = useNavigate()
    const location = useLocation()
    // ========================================= GLOBAL CONTEXT =========================================  //


    // ========================================= STATE VIEW =========================================  //
    const { linkUpId } = useParams()
    const { link_up, category_sensor } = location.state || {}

    const [machineData, setMachineData] = useState<{ [type: string]: MachineEntity[] }>({})
    const [tableDataFoll, setTableDataFoll] = useState<{ [id: string]: DashboardFollowingLevel3 }>({})

    interface DashboardLevel2State {
        link_up_id: number,
        link_up: string,

        ool_following_error: number,

        machine_ool: number[]
    }

    const [level2Data, setLevel2Data] = useState<{ [type: string]: DashboardLevel2State }>({})
    // ========================================= STATE VIEW =========================================  //


    // ========================================= FUNCTIONS =========================================  //
    const generateDataMachine = async () => {
        if (Object.keys(machineData).length == 0) { contextShowLoadingFunc(true) }
        try {
            const resp = await MachineService.GetAllMachine(linkUpId)

            const data: { [type: string]: MachineEntity[] } = {}
            for (let i = 0; i < resp.length; i++) {
                if (data[resp[i].machine_type] == undefined) {
                    data[resp[i].machine_type] = []
                }
                data[resp[i].machine_type].push(resp[i])
            }

            setMachineData(data)
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3, }))
        } finally {
            if (Object.keys(machineData).length == 0) { contextShowLoadingFunc(false) }
        }
    }

    const generateDataFollErr = async () => {
        try {
            if (linkUpId) {
                let resp: DashboardFollowingLevel3[] = []
                if (realtime) {
                    resp = await DashboardFollErrService.DashboardLevel3Realtime(Number(linkUpId))
                    onFilterDateChange({ start_date: new Date(), end_date: new Date() })
                    localStorage.removeItem("cache")
                } else {
                    const start_date = formatDate(filterDate.start_date, 'yyyy-MM-dd')
                    const end_date = formatDate(filterDate.end_date, 'yyyy-MM-dd')

                    resp = await DashboardFollErrService.DashboardLevel3(start_date, end_date, Number(linkUpId))
                    localStorage.setItem("cache", JSON.stringify({ ...filterDate, realtime }))
                }

                const data: { [id: string]: DashboardFollowingLevel3 } = {}
                const newLevel2ByType: { [type: string]: DashboardLevel2State } = {}
                for (let i = 0; i < resp.length; i++) {
                    const row = resp[i]
                    data[`${row.machine_id}`] = row

                    const machine = Object.values(machineData).flat().find(m => m.machine_id === row.machine_id)
                    if (!machine) continue

                    const machineType = machine.machine_type

                    if (!newLevel2ByType[machineType]) {
                        newLevel2ByType[machineType] = {
                            link_up_id: link_up.link_up_id,
                            link_up: link_up.link_up,
                            ool_following_error: 0,
                            machine_ool: [],
                        }
                    }

                    newLevel2ByType[machineType].ool_following_error += row.ool_following_error

                    if (row.ool_following_error > machine.machine_alarm) {
                        newLevel2ByType[machineType].machine_ool.push(machine.machine_id)
                    }
                }

                for (const type in newLevel2ByType) {
                    newLevel2ByType[type].machine_ool = Array.from(new Set(newLevel2ByType[type].machine_ool))
                }

                setLevel2Data(newLevel2ByType)
                setTableDataFoll(data)
            }
        } catch (error: any) {
            contextShowAlertFunc(new AlertEntity({ message: error instanceof Error ? error.message : error.toString(), level: 3, }))
        }
    }

    const getStatusOOL = (value: number | undefined, item: MachineEntity) => {
        const oolPressure = value ?? 0
        let result = ''
        if (oolPressure > item.machine_warn) {
            result = styles.warningBackground
        }
        if (oolPressure > item.machine_alarm) {
            result = styles.dangerBackground
        }
        return result
    }

    const generateData = async () => {
        if (realtime) {
            if (contextVersion.following != undefined) { await generateDataFollErr() }
        } else {
            resetAllData()
            contextShowLoadingFunc(true)
            // langsung tampilkan ketika udah ada yg selesai satu
            const promise = []
            if (contextVersion.following != undefined) { promise.push(generateDataFollErr()) }
            try { await Promise.any(promise) } catch { }
            contextShowLoadingFunc(false)
        }
    }

    const resetAllData = () => {
        setLevel2Data((prev) => {
            const reset: typeof prev = {}
            for (const type in prev) {
                reset[type] = {
                    ...prev[type],
                    ool_following_error: 0,
                    machine_ool: [],
                }
            }
            return reset
        })
        setTableDataFoll({})
    }

    useEffect(() => {
        if (Object.keys(machineData).length > 0) {
            generateData()
            if (realtime) {
                const interval = setInterval(generateData, 1000)

                return () => {
                    clearInterval(interval)
                }
            }
        }
    }, [contextAccessToken, realtime, linkUpId, machineData, refresh])

    // generate once
    useEffect(() => {
        generateDataMachine()
    }, [])
    // ========================================= FUNCTIONS =========================================  //


    return <div
        className={styles.cardWrapper}
        style={{
            gridTemplateColumns: Object.keys(machineData).length === 1 ? '1fr' : 'repeat(2, 1fr)',
            gridAutoRows: Object.keys(machineData).length <= 2 ? '1fr' : undefined
        }}
    >
        {Object.keys(machineData).map((val) => {
            const row = machineData[val]
            return < div className={styles.cardParent} key={val} >

                <div className={styles.cardParentHeader}>
                    <div className={styles.titleHeader}>
                        {val} Overall
                    </div>

                    <div className={styles.bodyHeader}>
                        <div className={styles.bodyHeaderLeft}>
                            <div className={styles.itemHeaderLeft}>
                                <div>Total Machine OOL</div>
                                <div className={styles.oolNumber}>{level2Data[val]?.machine_ool?.length ?? 0}</div>
                            </div>
                            <div className={styles.itemHeaderLeft}>
                                <div>Total OOL Following Error</div>
                                <div className={styles.oolNumber}>{level2Data[val]?.ool_following_error}</div>
                            </div>
                        </div>

                        <div className={styles.bodyHeaderRight}>
                            <div className={styles.imgWrapper}>
                                <img src={followingErrorImage} alt="following error image" className={styles.imgHeader} />
                            </div>
                        </div>
                    </div>
                </div>

                <div className={styles.cardParentBodyWrapper}>
                    <div className={styles.cardParentBody} style={{ gridTemplateColumns: Object.keys(machineData).length > 1 ? "repeat(2, 1fr)" : "repeat(4, 1fr)" }}>
                        {row.map((m) => {
                            const foll = tableDataFoll[`${m.machine_id}`]

                            return <div key={m.machine_id} className={styles.gridItem} style={{ backgroundImage: `url(${cardImage})` }}
                                onClick={() => navigate(`/dashboard/l4/${m.machine_id}`, {
                                    state: {
                                        dashboard_type: "follerr",
                                        machine: m.machine,
                                    },
                                })}>

                                <div className={styles.gridTitle}>
                                    <div className={styles.gridTitleText}>
                                        {m.machine}
                                    </div>
                                </div>
                                <div className={styles.gridContent}>

                                    {foll != undefined
                                        ? <>
                                            <div className={`${styles.gridContentText} ${getStatusOOL(foll.ool_following_error, m)}`} style={{ gridColumn: 'span 2' }}>
                                                <div>OOL Following Error</div>
                                                <div>{foll.ool_following_error}</div>
                                            </div>
                                        </>
                                        : <></>}

                                </div>
                            </div>
                        })}
                    </div>
                </div>

            </div>
        })}
    </div>
}

export default DashboardLevel3FollErrPage