import { BASE_URL } from "../constants"
import { MachineEntity } from "../entities/MachineEntity"
import FetchUtils from "../utils/fetch"

class MachineService {
    static async GetAllMachine(link_up_id?: string): Promise<MachineEntity[]> {
        let uri = `${BASE_URL}/api/v1/machine`
        if (link_up_id != null){
            uri += `?link_up_id=${link_up_id}`
        }

        const resp = await FetchUtils.fetchAuth(uri)
        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        const rawData = Array.isArray(resp.data) ? resp.data : []
        const data: MachineEntity[] = []
        for (let i = 0; i < rawData.length; i++) {
            data.push({
                machine_id: rawData[i].machine_id,
                machine: rawData[i].machine,
                machine_warn: rawData[i].machine_warn,
                machine_alarm: rawData[i].machine_alarm,
                link_up: rawData[i].link_up,
                machine_type: rawData[i].machine_type,
                gateway_host: rawData[i].gateway_host,
                gateway_port: rawData[i].gateway_port,
                pressure_slave_id: rawData[i].pressure_slave_id,
                vibration_slave_id: rawData[i].vibration_slave_id,
            })
        }

        return data
    }

    static async AddMachine(data: {
        machine: string,
        machine_warn: number,
        machine_alarm: number,
        link_up_id: number,
        machine_type: string,
        gateway_host: string,
        gateway_port: string,
        pressure_slave_id?: number,
        vibration_slave_id?: number,
    }): Promise<{ message: string }> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/machine`,
            {
                method: 'POST',
                body: JSON.stringify({ ...data }),
                headers: { "Content-Type": "application/json" }
            }
        )

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }

    static async UpdateMachine(machine_id: number, fields: {
        machine?: string,
        machine_warn?: number,
        machine_alarm?: number,
        link_up_id?: number,
        machine_type?: string,
        gateway_host?: string,
        gateway_port?: string,
        pressure_slave_id?: number,
        vibration_slave_id?: number,
    }): Promise<{ message: string }> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/machine`,
            {
                method: 'PATCH',
                body: JSON.stringify({ machine_id, fields }),
                headers: { "Content-Type": "application/json" }
            }
        )

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }

    static async DeleteMachine(machine_id: number): Promise<{ message: string }> {
        let resp = await FetchUtils.fetchAuth(`${BASE_URL}/api/v1/machine`,
            {
                method: 'DELETE',
                body: JSON.stringify({ machine_id: machine_id }),
                headers: { "Content-Type": "application/json" }
            }
        )

        if (resp.status !== 200) {
            throw new Error(resp.message)
        }

        return resp
    }
}

export { MachineService }